import type { Metadata } from "next";
import { Geist, Geist_Mono } from "next/font/google";
import "./globals.css";
import { auth } from "@/lib/auth";
import { signOut } from "@/lib/actions";
import Link from "next/link";
import { Compass, Package, ShoppingCart, BarChart2, User, LogOut, LayoutDashboard } from "lucide-react";

const geistSans = Geist({
  variable: "--font-geist-sans",
  subsets: ["latin"],
});

const geistMono = Geist_Mono({
  variable: "--font-geist-mono",
  subsets: ["latin"],
});

export const metadata: Metadata = {
  title: "Lojinha Escoteira - Controle de Estoque",
  description: "Sistema de controle de estoque e vendas para grupo escoteiro",
};

export default async function RootLayout({
  children,
}: Readonly<{
  children: React.ReactNode;
}>) {
  const session = await auth();

  return (
    <html lang="pt-BR" suppressHydrationWarning>
      <body
        className={`${geistSans.variable} ${geistMono.variable} antialiased min-h-screen flex flex-col bg-scout-khaki`}
      >
        {session && (
          <header className="bg-scout-green text-white shadow-lg sticky top-0 z-50 border-b-4 border-scout-yellow">
            <div className="container mx-auto px-4 flex justify-between items-center h-20">
              <Link href="/" className="flex items-center gap-3 group">
                <div className="bg-white/10 p-2 rounded-xl border border-white/20 group-hover:bg-scout-yellow/10 transition-colors">
                  <Compass className="w-8 h-8 text-scout-yellow" />
                </div>
                <div className="flex flex-col -gap-1">
                  <span className="font-black text-lg tracking-tight leading-tight">LOJINHA</span>
                  <span className="font-medium text-[10px] tracking-[0.3em] uppercase opacity-70">Escoteira</span>
                </div>
              </Link>
              
              <nav className="flex items-center gap-2 lg:gap-4">
                <Link href="/" className="nav-link-scout">
                  <LayoutDashboard className="w-5 h-5" />
                  <span className="hidden md:inline">Início</span>
                </Link>
                <Link href="/estoque" className="nav-link-scout">
                  <Package className="w-5 h-5" />
                  <span className="hidden md:inline">Estoque</span>
                </Link>
                <Link href="/vendas" className="nav-link-scout">
                  <ShoppingCart className="w-5 h-5" />
                  <span className="hidden md:inline">Vendas</span>
                </Link>
                <Link href="/vendas/dashboard" className="nav-link-scout">
                  <BarChart2 className="w-5 h-5" />
                  <span className="hidden md:inline">Relatórios</span>
                </Link>
                {session.user?.role === 'ADMIN' && (
                  <Link href="/admin" className="nav-link-scout">
                    <User className="w-5 h-5" />
                    <span className="hidden md:inline">Admin</span>
                  </Link>
                )}
              </nav>

              <div className="flex items-center gap-4 pl-4 border-l border-white/20">
                <div className="hidden lg:flex flex-col items-end">
                  <span className="text-[10px] font-black uppercase tracking-widest opacity-60">Sempre Alerta</span>
                  <span className="text-xs font-bold text-scout-yellow truncate max-w-[120px]">
                    {session.user?.name?.split(' ')[0]}
                  </span>
                </div>
                <form action={signOut}>
                  <button type="submit" className="p-2 hover:bg-white/10 rounded-full transition-colors text-white/80 hover:text-red-400">
                    <LogOut className="w-5 h-5" />
                  </button>
                </form>
              </div>
            </div>
          </header>
        )}
        <main className="flex-grow container mx-auto px-4 py-8 max-w-7xl">
          {children}
        </main>
        <footer className="bg-scout-green/10 py-10 border-t border-scout-green/5">
          <div className="container mx-auto px-4 flex flex-col items-center gap-4">
            <Compass className="w-8 h-8 text-scout-green opacity-20" />
            <div className="text-center">
              <p className="text-scout-green/60 font-black uppercase text-[10px] tracking-[0.5em] mb-1">Grupo Escoteiro</p>
              <p className="text-scout-green font-bold italic">"Sempre Alerta!"</p>
            </div>
            <p className="text-[15px] text-scout-green/40 mt-4 uppercase font-medium">© 2026 Sistema de Lojinha Integrad - DEV Pai da Mirian</p>
          </div>
        </footer>
      </body>
    </html>
  );
}
